#!/bin/bash
# ============================================
# feishu-bridge 全自动部署（自包含，无需 GitHub）
# ============================================
set -e
GREEN='\033[0;32m'; RED='\033[0;31m'; YELLOW='\033[1;33m'; NC='\033[0m'
DIR="/opt/feishu-bridge"

echo -e "${GREEN}========================================${NC}"
echo -e "${GREEN}  feishu-bridge 全自动部署${NC}"
echo -e "${GREEN}========================================${NC}"

# 1. 创建目录
echo -e "\n${YELLOW}[1/8] 创建目录...${NC}"
mkdir -p "$DIR" && cd "$DIR"

# 2. 加载 Node.js
echo -e "\n${YELLOW}[2/8] 加载 Node.js...${NC}"
export NVM_DIR="$HOME/.nvm"
[ -s "$NVM_DIR/nvm.sh" ] && . "$NVM_DIR/nvm.sh"
if ! command -v node &>/dev/null; then
  echo -e "${RED}Node.js 未安装，正在安装 nvm + node 22...${NC}"
  curl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.39.7/install.sh | bash
  export NVM_DIR="$HOME/.nvm"
  [ -s "$NVM_DIR/nvm.sh" ] && . "$NVM_DIR/nvm.sh"
  nvm install 22
fi
echo "Node.js $(node -v) ✓"

# 3. 写入文件
echo -e "\n${YELLOW}[3/8] 写入文件...${NC}"
echo '' | base64 -d > server.js
echo '' | base64 -d > package.json
echo '' | base64 -d > .env.example
echo 'IyDpo57kuaYgR2F0ZXdheSDmoaXmjqXmnI3liqEgRG9ja2VyZmlsZQpGUk9NIG5vZGU6MjItYWxwaW5lCgpXT1JLRElSIC9hcHAKCkNPUFkgcGFja2FnZSouanNvbiAuLwpSVU4gbnBtIGluc3RhbGwgLS1wcm9kdWN0aW9uCgpDT1BZIC4gLgoKRVhQT1NFIDMwMDAKCkNNRCBbIm5vZGUiLCAic2VydmVyLmpzIl0K' | base64 -d > Dockerfile
echo '' | base64 -d > feishu-bridge.service
echo 'bm9kZV9tb2R1bGVzLwouZW52CioubG9nCi5EU19TdG9yZQo=' | base64 -d > .gitignore

# 4. 创建 .env
echo -e "\n${YELLOW}[4/8] 创建配置...${NC}"
[ ! -f .env ] && cp .env.example .env
echo ".env ✓"

# 5. 安装依赖
echo -e "\n${YELLOW}[5/8] 安装依赖...${NC}"
npm install --production
echo -e "${GREEN}依赖安装完成 ✓${NC}"

# 6. 安装 PM2
echo -e "\n${YELLOW}[6/8] 安装 PM2...${NC}"
npm install -g pm2 2>/dev/null || true
echo "PM2 ✓"

# 7. 启动服务
echo -e "\n${YELLOW}[7/8] 启动服务...${NC}"
pm2 delete feishu-bridge 2>/dev/null || true
pm2 start server.js --name feishu-bridge
pm2 save 2>/dev/null || true
pm2 startup 2>/dev/null || true

# 8. 验证
echo -e "\n${YELLOW}[8/8] 验证服务...${NC}"
sleep 3
curl -s http://localhost:3000/health && echo "" || echo -e "${RED}健康检查失败，查看日志: pm2 logs feishu-bridge${NC}"

pm2 status

echo -e "\n${GREEN}========================================${NC}"
echo -e "${GREEN}  部署完成！${NC}"
echo -e "${GREEN}========================================${NC}"
echo ""
echo "⚠ 下一步："
echo "  1. 编辑配置: vim /opt/feishu-bridge/.env"
echo "     填入 FEISHU_APP_SECRET 和 FEISHU_VERIFICATION_TOKEN"
echo "  2. 重启: pm2 restart feishu-bridge"
echo "  3. 腾讯云安全组开放端口 3000"
echo "  4. 飞书后台配置: http://82.156.199.62:3000/feishu/callback"
